import React, { useEffect, useState } from 'react';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import api from '../api';
import './Navbar.css';

export default function Navbar() {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const location = useLocation();
  const [unread, setUnread] = useState(0);

  useEffect(() => {
    let cancelled = false;
    const fetchUnread = async () => {
      try {
        const res = await api.get('/dashboard');
        if (!cancelled) setUnread(res.data.unreadCount || 0);
      } catch {}
    };
    fetchUnread();
    const interval = setInterval(fetchUnread, 10000);
    return () => { cancelled = true; clearInterval(interval); };
  }, [location.pathname]);

  const handleLogout = () => { logout(); navigate('/login'); };

  const isActive = (path) => location.pathname === path ? 'active' : '';

  return (
    <nav className="navbar">
      <div className="navbar-brand">
        <span className="brand-icon">🩸</span>
        <span className="brand-name">LifeLink</span>
      </div>
      <div className="navbar-links">
        <Link to="/dashboard"      className={isActive('/dashboard')}>Dashboard</Link>
        <Link to="/register-donor" className={isActive('/register-donor')}>Register Donor</Link>
        <Link to="/request"        className={isActive('/request')}>Emergency Request</Link>
        <Link to="/profile"        className={isActive('/profile')}>Profile</Link>
        <Link to="/notifications"  className={`notif-link ${isActive('/notifications')}`}>
          Notifications
          {unread > 0 && <span className="notif-badge">{unread}</span>}
        </Link>
      </div>
      <div className="navbar-user">
        <span className="user-role">{user?.role}</span>
        <span className="user-name">{user?.name}</span>
        <button className="btn btn-secondary btn-sm" onClick={handleLogout}>Logout</button>
      </div>
    </nav>
  );
}
